import { MinPriorityQueue } from 'datastructures-js/priority-queue';

function solve(n, edges) {
    // Build adjacency list
    const adj = Array.from({ length: n }, () => []);
    for (const [u, v, start, end] of edges) {
        adj[u].push([v, start, end]);
    }

    // Priority queue: [current_time, node]
    const heap = new MinPriorityQueue({
        priority: (item) => item[0]
    });
    heap.enqueue([0, 0]);

    // Visited dictionary to keep track of the earliest time we've seen each node
    const visited = new Map();
    visited.set(0, 0);

    while (!heap.isEmpty()) {
        const { element: [current_time, u] } = heap.dequeue();
        if (u === n - 1) {
            return current_time;
        }

        if (current_time > (visited.get(u) || Infinity)) {
            continue;
        }

        // Option 1: Stay at current node (time increases by 1)
        const new_time = current_time + 1;
        if (new_time < (visited.get(u) || Infinity)) {
            visited.set(u, new_time);
            heap.enqueue([new_time, u]);
        }

        // Option 2: Take an outgoing edge if possible
        for (const [v, start, end] of adj[u]) {
            // The earliest we can take this edge is max(current_time, start)
            const t = Math.max(current_time, start);
            if (t <= end) {
                const arrival_time = t + 1;
                if (arrival_time < (visited.get(v) || Infinity)) {
                    visited.set(v, arrival_time);
                    heap.enqueue([arrival_time, v]);
                }
            }
        }
    }

    return -1;
}
